    10→ * - Enforcing co-presence rules and allowed combinations
    11→ * - Determining AI classification requirements
    12→ * - Generating complete selection rationale and audit trails
    13→ */
    14→
    15→import { CategoryScore, MultiLabelConfig, ConfidenceThresholds, SelectedLabel } from './types';
    16→import { ClassificationSession } from '../types/classification-session';
    17→import { ClassificationResult } from '../types/classification-result';
    18→import { EmailMessage } from '../types/email-message';
    19→
    20→/**
    21→ * Execute multi-label selection stage (canonical signature)
    22→ *
    23→ * Ranks categories, selects primary/secondary labels, and determines AI routing needs.
    24→ *
    25→ * Mutates the result object in place by setting primaryCategory, secondaryCategories,
    26→ * and updating explainability trace with selection decisions.
    27→ *
    28→ * @param email - Email message being classified (canonical signature parameter, not used directly)
    29→ * @param session - Classification session batch metadata (canonical signature parameter, not used directly)
    30→ * @param result - Classification result to update (mutated in place)
    31→ * @param config - Multi-label selection configuration
    32→ * @param thresholds - Confidence thresholds for label selection
    33→ */
    34→export function executeMultiLabelSelection(
    35→  _email: EmailMessage,
    36→  _session: ClassificationSession,
    37→  result: ClassificationResult,
    38→  config: MultiLabelConfig,
    39→  thresholds: ConfidenceThresholds
    40→): void {
    41→  const startTime = Date.now();
    42→
    43→  // Validate configuration
    44→  validateConfiguration(config, thresholds);
    45→
    46→  // Extract candidate scores from result.scoreBreakdown
    47→  const candidateScores: Record<string, CategoryScore> = {};
    48→  for (const [category, scoreData] of Object.entries(result.scoreBreakdown.categoryScores)) {
    49→    candidateScores[category] = {
    50→      score: scoreData.finalScore || scoreData.baseScore || 0,
    51→      confidence: scoreData.confidence || 0, // Use calculated confidence from scoring stages
    52→      rationale: '',
    53→      decision: undefined,
    54→      selectedSubtypeId: scoreData.selectedSubtypeId,
    55→    };
    56→  }
    57→
    58→  // Rank categories by score
    59→  const rankedCategories = rankCategoriesByScore(candidateScores);
    60→
    61→  if (rankedCategories.length === 0) {
    62→    const duration = Date.now() - startTime;
    63→    result.processingDurationMs += duration;
    64→    result.explainabilityTrace.stageTimings['multiLabelSelection'] = duration;
    65→    result.explainabilityTrace.configurationRefs['multiLabelSelection'] = 'settings.multiLabelSelection';
    66→
    67→    // Create a MultiLabelResult explaining why no categories were selected
    68→    result.explainabilityTrace.multiLabelSelection = [
    69→      {
    70→        selectedCategories: [],
    71→        rejectedCategories: [],
    72→        coPresenceRulesApplied: [],
    73→        maxLabelsLimit: config.maxLabels,
    74→        minSecondaryConfidence: thresholds.lowConfidenceThreshold,
    75→        reason: 'No candidate categories available from previous scoring stages',
    76→      },
    77→    ];
    78→
    79→    // Populate empty pipeline fields when no candidates exist
    80→    result.selectedLabels = [];
    81→    result.candidateScores = {};
    82→    result.needsAiClassification = true; // No categories = needs AI help
    83→    result.selectionSummary = {
    84→      totalLabels: 0,
    85→      primaryCategory: null,
    86→      confidenceRange: [0, 0],
    87→      selectionMethod: 'noneSelected',
    88→      needsAi: true,
    89→      topCategories: [],
    90→    };
    91→
    92→    return;
    93→  }
    94→
    95→  const selectedLabels: SelectedLabel[] = [];
    96→
    97→  // Select primary label
    98→  const primaryCandidate = rankedCategories[0];
    99→  if (primaryCandidate.score >= thresholds.lowConfidenceThreshold) {
   100→    const primaryLabel: SelectedLabel = {
   101→      category: primaryCandidate.category,
   102→      subtype: primaryCandidate.selectedSubtypeId || null,
   103→      confidence: primaryCandidate.confidence,
   104→      score: primaryCandidate.score,
   105→      isPrimary: true,
   106→      labelOrder: 1,
   107→      selectionRationale: `Primary label: highest score (${primaryCandidate.score}) above minimum threshold (${thresholds.lowConfidenceThreshold})`,
   108→    };
   109→    selectedLabels.push(primaryLabel);
   110→
   111→    // Select secondary labels
   112→    selectSecondaryLabels(rankedCategories, selectedLabels, primaryCandidate, config, thresholds);
   113→  }
   114→
   115→  // Update category decisions
   116→  updateCategoryDecisions(candidateScores, selectedLabels, thresholds);
   117→
   118→  // Determine AI classification need
   119→  const needsAiClassification = determineAiClassificationNeed(selectedLabels, thresholds);
   120→
   121→  const duration = Date.now() - startTime;
   122→
   123→  // Mutate result: Update primary and secondary categories
   124→  if (selectedLabels.length > 0) {
   125→    const primaryLabel = selectedLabels.find((l) => l.isPrimary) || selectedLabels[0];
   126→    result.primaryCategory = primaryLabel.category;
   127→    result.subtype = primaryLabel.subtype; // Flatten subtype to top level for easy access
   128→    result.secondaryCategories = selectedLabels.filter((l) => !l.isPrimary).map((l) => l.category);
   129→    result.confidence = primaryLabel.confidence / 100; // Normalize to 0-1
   130→  }
   131→
   132→  // Update AI routing flag
   133→  result.aiRoutingUsed = needsAiClassification;
   134→
   135→  // Populate pipeline-oriented fields for persistence layer and tests
   136→  result.selectedLabels = selectedLabels;
   137→  result.candidateScores = candidateScores;
   138→  result.needsAiClassification = needsAiClassification;
   139→  result.selectionSummary = {
   140→    totalLabels: selectedLabels.length,
   141→    primaryCategory: selectedLabels.find((l) => l.isPrimary)?.category || null,
   142→    confidenceRange:
   143→      selectedLabels.length > 0
   144→        ? [Math.min(...selectedLabels.map((l) => l.confidence)), Math.max(...selectedLabels.map((l) => l.confidence))]
   145→        : [0, 0],
   146→    selectionMethod:
   147→      selectedLabels.length === 0 ? 'noneSelected' : selectedLabels.length === 1 ? 'singleLabel' : 'multiLabel',
   148→    needsAi: needsAiClassification,
   149→    topCategories: rankedCategories.slice(0, 5).map((cat) => ({
   150→      category: cat.category,
   151→      score: cat.score,
   152→    })),
   153→  };
   154→
   155→  // Update result processing duration
   156→  result.processingDurationMs += duration;
   157→
   158→  // Add parallel stage result tracking
   159→  result.parallelStageResults.push({
   160→    stageId: `multi_label_selection_${result.id}`,
   161→    stageName: 'multiLabelSelection',
   162→    executionTimeMs: duration,
   163→    parallelWithStages: [],
   164→    dependentOnStages: ['disambiguation'],
   165→    cacheHitsCount: 0,
   166→    errorCount: 0,
   167→  });
   168→
   169→  // Update explainability trace (convert to ExplainabilityTrace.MultiLabelResult format)
   170→  const multiLabelResults: Array<{
   171→    selectedCategories: string[];
   172→    rejectedCategories: Array<{
   173→      category: string;
   174→      score: number;
   175→      rejectionReason: string;
   176→    }>;
   177→    coPresenceRulesApplied: string[];
   178→    maxLabelsLimit: number;
   179→    minSecondaryConfidence: number;
   180→    reason: string;
   181→  }> = [
   182→    {
   183→      selectedCategories: selectedLabels.map((l) => l.category),
   184→      rejectedCategories: rankedCategories
   185→        .filter((cat) => !selectedLabels.some((l) => l.category === cat.category))
   186→        .map((cat) => ({
   187→          category: cat.category,
   188→          score: cat.score,
   189→          rejectionReason:
   190→            cat.score < thresholds.lowConfidenceThreshold
   191→              ? `Below minimum threshold (${cat.score} < ${thresholds.lowConfidenceThreshold})`
   192→              : 'Exceeded max labels limit or failed combination rules',
   193→        })),
   194→      coPresenceRulesApplied: [], // Populated based on allowed combinations
   195→      maxLabelsLimit: config.maxLabels,
   196→      minSecondaryConfidence: config.mediumConfidenceThreshold,
   197→      reason:
   198→        selectedLabels.length > 0
   199→          ? `Selected ${selectedLabels.length} labels with primary: ${selectedLabels.find((l) => l.isPrimary)?.category || selectedLabels[0].category}`
   200→          : 'No labels met minimum confidence threshold',
   201→    },
   202→  ];
   203→
   204→  result.explainabilityTrace.multiLabelSelection = multiLabelResults;
   205→  result.explainabilityTrace.stageTimings['multiLabelSelection'] = duration;
   206→  result.explainabilityTrace.configurationRefs['multiLabelSelection'] = 'settings.multiLabelSelection';
   207→}
   208→
   209→/**
   210→ * Validate configuration parameters
   211→ */
   212→function validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
   213→  if (config.maxLabels < 0) {
   214→    throw new Error('Invalid configuration: maxLabels cannot be negative');
   215→  }
   216→
   217→  if (config.mediumConfidenceThreshold < 0) {
   218→    throw new Error('Invalid configuration: minSecondaryConfidence cannot be negative');
   219→  }
   220→
   221→  if (thresholds.highConfidenceThreshold <= thresholds.mediumConfidenceThreshold) {
   222→    throw new Error('Invalid threshold configuration: highConfidence must be greater than mediumConfidence');
   223→  }
   224→
   225→  if (thresholds.mediumConfidenceThreshold <= thresholds.lowConfidenceThreshold) {
   226→    throw new Error('Invalid threshold configuration: mediumConfidence must be greater than lowConfidence');
   227→  }
   228→
   229→  if (thresholds.secondaryLabelMinGap < 0) {
   230→    throw new Error('Invalid threshold configuration: secondaryLabelMinGap cannot be negative');
   231→  }
   232→}
   233→
   234→/**
   235→ * Rank categories by score in descending order, filtering out zero/negative scores
   236→ */
   237→function rankCategoriesByScore(candidateScores: Record<string, CategoryScore>): Array<{
   238→  category: string;
   239→  score: number;
   240→  confidence: number;
   241→  rationale: string;
   242→  selectedSubtypeId?: string | null;
   243→}> {
   244→  return Object.entries(candidateScores)
   245→    .map(([category, scoreData]) => ({
   246→      category,
   247→      score: scoreData.score || 0,
   248→      confidence: scoreData.confidence || 0,
   249→      rationale: scoreData.rationale || '',
   250→      selectedSubtypeId: scoreData.selectedSubtypeId,
   251→    }))
   252→    .filter((item) => item.score > 0)
   253→    .sort((a, b) => {
   254→      // Primary sort by score (descending)
   255→      if (b.score !== a.score) {
   256→        return b.score - a.score;
   257→      }
   258→      // Secondary sort by category name for stable ordering
   259→      return a.category.localeCompare(b.category);
   260→    });
   261→}
   262→
   263→/**
   264→ * Select secondary labels within gap threshold and above minimum confidence
   265→ */
   266→function selectSecondaryLabels(
   267→  rankedCategories: Array<{
   268→    category: string;
   269→    score: number;
   270→    confidence: number;
   271→    rationale: string;
   272→    selectedSubtypeId?: string | null;
   273→  }>,
   274→  selectedLabels: SelectedLabel[],
   275→  primaryCandidate: {
   276→    category: string;
   277→    score: number;
   278→    confidence: number;
   279→    rationale: string;
   280→    selectedSubtypeId?: string | null;
   281→  },
   282→  config: MultiLabelConfig,
   283→  thresholds: ConfidenceThresholds
   284→): void {
   285→  if (config.maxLabels <= 1 || rankedCategories.length <= 1) {
   286→    return;
   287→  }
   288→
   289→  const primaryScore = primaryCandidate.score;
   290→
   291→  for (let i = 1; i < rankedCategories.length && selectedLabels.length < config.maxLabels; i++) {
   292→    const candidate = rankedCategories[i];
   293→    const scoreDifference = primaryScore - candidate.score;
   294→
   295→    // Check if candidate meets secondary label criteria
   296→    // candidate.confidence is on 0-100 scale, config.mediumConfidenceThreshold is on 0-1 scale
   297→    const normalizedConfidence = candidate.confidence / 100;
   298→    if (
   299→      normalizedConfidence >= config.mediumConfidenceThreshold &&
   300→      scoreDifference <= thresholds.secondaryLabelMinGap
   301→    ) {
   302→      // Check if combination is allowed
   303→      if (isCombinationAllowed(primaryCandidate.category, candidate.category, config)) {
   304→        const secondaryLabel: SelectedLabel = {
   305→          category: candidate.category,
   306→          subtype: candidate.selectedSubtypeId || null,
   307→          confidence: candidate.confidence,
   308→          score: candidate.score,
   309→          isPrimary: false,
   310→          labelOrder: selectedLabels.length + 1,
   311→          selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${thresholds.secondaryLabelMinGap}) and above minimum confidence (${config.mediumConfidenceThreshold})`,
   312→        };
   313→        selectedLabels.push(secondaryLabel);
   314→      }
   315→    }
   316→  }
   317→}
   318→
   319→/**
   320→ * Check if category combination is allowed based on configuration
   321→ */
   322→function isCombinationAllowed(primaryCategory: string, candidateCategory: string, config: MultiLabelConfig): boolean {
   323→  if (primaryCategory === candidateCategory) {
   324→    return true;
   325→  }
   326→
   327→  // If strict mode is enabled and combinations are specified, only allow explicit combinations
   328→  if (config.strictCombinationMode && config.allowedCombinations.length > 0) {
   329→    return config.allowedCombinations.some((combo) => {
   330→      const categories = combo.categories;
   331→      return categories && categories.includes(primaryCategory) && categories.includes(candidateCategory);
   332→    });
   333→  }
   334→
   335→  // If no combinations specified, allow all (default permissive mode)
   336→  if (config.allowedCombinations.length === 0) {
   337→    return true;
   338→  }
   339→
   340→  // If combinations are specified but not in strict mode, still check them
   341→  const isExplicitlyAllowed = config.allowedCombinations.some((combo) => {
   342→    const categories = combo.categories;
   343→    return categories && categories.includes(primaryCategory) && categories.includes(candidateCategory);
   344→  });
   345→
   346→  // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
   347→  return isExplicitlyAllowed || !config.strictCombinationMode;
   348→}
   349→
   350→/**
   351→ * Update category decisions based on selection results
   352→ */
   353→function updateCategoryDecisions(
   354→  candidateScores: Record<string, CategoryScore>,
   355→  selectedLabels: SelectedLabel[],
   356→  thresholds: ConfidenceThresholds
   357→): void {
   358→  const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));
   359→
   360→  for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
   361→    const score = scoreData.score || 0;
   362→
   363→    if (selectedCategoryNames.has(categoryCode)) {
   364→      // Selected categories get decision based on confidence
   365→      if (score >= thresholds.highConfidenceThreshold) {
   366→        scoreData.decision = 'selected';
   367→        scoreData.decisionRationale = `High confidence (${score} >= ${thresholds.highConfidenceThreshold}) - finalized without AI`;
   368→      } else if (score >= thresholds.mediumConfidenceThreshold) {
   369→        scoreData.decision = 'candidate';
   370→        scoreData.decisionRationale = `Medium confidence (${score} >= ${thresholds.mediumConfidenceThreshold}) - may need AI validation`;
   371→      } else {
   372→        scoreData.decision = 'candidate';
   373→        scoreData.decisionRationale = `Low confidence (${score} >= ${thresholds.lowConfidenceThreshold}) - needs AI classification`;
   374→      }
   375→    } else {
   376→      // Non-selected categories are rejected
   377→      scoreData.decision = 'rejected';
   378→      if (score < thresholds.lowConfidenceThreshold) {
   379→        scoreData.decisionRationale = `Below minimum threshold (${score} < ${thresholds.lowConfidenceThreshold})`;
   380→      } else {
   381→        scoreData.decisionRationale = `Not selected despite adequate score (${score}) due to multi-label constraints`;
   382→      }
   383→    }
   384→  }
   385→}
   386→
   387→/**
   388→ * Determine if AI classification is needed based on selected labels
   389→ */
   390→function determineAiClassificationNeed(selectedLabels: SelectedLabel[], thresholds: ConfidenceThresholds): boolean {
   391→  if (selectedLabels.length === 0) {
   392→    return true; // No labels selected - need AI
   393→  }
   394→
   395→  // Check if primary label has high confidence (can skip AI)
   396→  // NOTE: confidence is on 0-100 scale, thresholds are on 0-1 scale
   397→  const primaryLabel = selectedLabels.find((label) => label.isPrimary);
   398→  if (primaryLabel && primaryLabel.confidence / 100 >= thresholds.highConfidenceThreshold) {
   399→    return false; // High confidence primary - skip AI
   400→  }
   401→
   402→  // Check if any label is below medium confidence (needs AI)
   403→  const hasLowConfidenceLabel = selectedLabels.some(
   404→    (label) => label.confidence / 100 < thresholds.mediumConfidenceThreshold
   405→  );
   406→  if (hasLowConfidenceLabel) {
   407→    return true; // Has low confidence labels - need AI
   408→  }
   409→
   410→  // Medium confidence range - labels are acceptable, skip AI
   411→  return false;
   412→}
