 * Request for configuration validation endpoint
 */
export interface ConfigValidationRequest {
  configuration: unknown; // Flexible to allow invalid configs in tests
  validateAgainstSchema?: boolean;
  generateCompiledRules?: boolean;
}

/**
 * Response from configuration validation endpoint
 */
export interface ConfigValidationResponse {
  valid: boolean;
  errors: ValidationError[];
  warnings: ValidationWarning[];
  compiledRules?: CompiledRule[];
  compilationMetrics?: {
    rulesGenerated: number;
    optimizationsApplied: number;
    compilationDurationMs: number;
  };
}

/**
 * Validation error details
 */
export interface ValidationError {
  path: string;
  message: string;
  code: string;
  severity: 'error' | 'warning';
}

/**
 * Validation warning details
 */
export interface ValidationWarning {
  path: string;
  message: string;
  suggestion?: string;
}

/**
 * Compiled rule for performance optimization
 *
 * For positive matching operations (containsAny, startsWith, regexAny, etc.),
 * the pattern field contains the compiled RegExp.
 *
 * For negative matching operations (notContains), the operation and values
 * fields are used instead, and pattern is null.
 */
export interface CompiledRule {
  id: string;
  category: string;
  subtype?: string;
  pattern: RegExp | null; // null for negative operations like notContains
  weight: number;
  tier: 'high' | 'medium' | 'low';
  operation?: string; // For negative operations: 'notContains'
  values?: string[]; // For negative operations: the values to check
  field?: string; // For negative operations: the field to check (subject, body, etc.)
}

/**
 * Classification error details
 */
export interface ClassificationError {
  emailId: string;
  stage: string;
  error: string;
  timestamp: Date;
  recoverable: boolean;
}

